"""# Preparando data para Time Series Bovino"""

mx_exports = pd.read_csv('EXPORTS-MEXICO-TRIMESTRALES-2013-2024.csv')
display(mx_exports.head(30))

mx_exports.columns = [
    re.search(r"\b(20\d{2})\b", col).group(1)
    if "Valor exportado en" in col
    else col
    for col in mx_exports.columns
]

mx_exports.head()

"""### Preparación de la serie de tiempo

Voy a seleccionar únicamente los productos Carne Bovino y Porcino. Son los productos 0201 - 0203.

01 y 02 son los dos Bovinos. Voy a juntarlos en una sola serie de tiempo.
"""

# --- 1) Renombrar columnas de año repetidas a fechas (primer día de cada trimestre) ---
year_seen = defaultdict(int)
new_cols = []

for col in mx_exports.columns:
    col_str = str(col).strip()
    if re.fullmatch(r"\d{4}", col_str):  # columnas tipo "2013", "2014", ...
        year = int(col_str)
        year_seen[year] += 1
        q = year_seen[year]  # 1,2,3,4,...
        month = 1 + (q - 1) * 3
        new_cols.append(pd.Timestamp(year=year, month=month, day=1))
    else:
        new_cols.append(col)

mx_exports = mx_exports.copy()
mx_exports.columns = new_cols

# --- 2) Melt usando las fechas trimestrales ---
date_cols = [c for c in mx_exports.columns if isinstance(c, pd.Timestamp)]

mx_exports_long = mx_exports.melt(
    id_vars=[c for c in mx_exports.columns if c not in date_cols],
    value_vars=date_cols,
    var_name="Time",
    value_name="valor_exportado"
)

# --- 3) Serie bovino (0201 + 0202) por trimestre ---
ts_bovino = (
    mx_exports_long[mx_exports_long["Código"].isin(["'0201", "'0202"])]
    .groupby("Time", as_index=False)["valor_exportado"]
    .sum()
    .sort_values("Time")
)

display(ts_bovino)

# Hacer Time el índice (serie temporal)
ts_bovino = ts_bovino.set_index("Time")

display(ts_bovino)

"""# <font color='blue'> Análisis Descriptivo Tradicional"""

ts_bovino.describe()

"""Hay 48 registros del valor de exportaciones para el mercado cárnico, con un monto promedio de 358,965 USD. El 75% del valor de las exportaciones son igual o menores a 489,323.

El valor mínimo exportado es de 151,877, en el 2013, en el primer trimestre con el que contamos.
"""

plt.figure(figsize=(8, 6))

ax = sns.lineplot(
    data=ts_bovino,
    x=ts_bovino.index,
    y="valor_exportado"
)

plt.title('Valor Exportado de Carne Bovina (México a Estados Unidos)')
plt.xlabel('')
plt.ylabel('Valor exportado (miles de dólares)')

sns.despine(ax=ax)

# Mostrar etiqueta solo cada año
ax.xaxis.set_major_locator(mdates.YearLocator())
ax.xaxis.set_major_formatter(mdates.DateFormatter('%Y'))

plt.xticks(rotation=45)

# Formato eje Y
ax.yaxis.set_major_formatter(
    ticker.FuncFormatter(lambda x, pos: f'${int(x):,}')
)

plt.show()

"""En la última semana, esta serie de tiempo parece mostrar un comportamiento creciente a simple vista, mientras que la serie A parece tener un comportamiento decreciente.

# <font color='blue'> TREND ANALYSIS

## REGRESSION
"""

ts_bovino['Time'] = np.arange(len(ts_bovino.index))

spec = ModelSpec(['Time'])

X = spec.fit_transform(ts_bovino)
y=ts_bovino['valor_exportado']

model = sm.OLS(y, X)
model_fit = model.fit()

ts_bovino['Regression'] = model_fit.predict(X)
print(model_fit.summary())

"""Veamos el trend:"""

plt.figure(figsize=(10, 6))
ax=sns.regplot(x='Time', y='valor_exportado', data=ts_bovino, scatter=False, ci=None, line_kws={'color': 'red', 'ls':'--'}) #ci= None es para quitar los intervalos de confianza
sns.lineplot(ts_bovino, x='Time', y='valor_exportado', color='#57B9FF')
plt.title('Regression Plot')
plt.xlabel('Time (Quarters)')
plt.ylabel('valor_exportado')
ax.yaxis.set_major_formatter(ticker.FuncFormatter(lambda x, pos: f'${int(x):,}'))# y-axis in $$


plt.show()

"""# <font color='blue'> SMOOTHING

Decidí utilizar Exponential Smoothing para el análisis de suavizamiento y contar la historia ya que esta es una herramienta más poderosa que solo un reductor de picos.

## Exponential Smoothing
"""

y = ts_bovino["valor_exportado"].asfreq("QS")

exp_model = ExponentialSmoothing(
    y,
    trend="add",
    seasonal="add",        # prueba también "mul"
    seasonal_periods=4
).fit(optimized=True)

"""Definamos cuántos Qs queremos en nuestros forecasts:"""

forecast_horizon_q = 8
forecast = exp_model.forecast(forecast_horizon_q)

"""Creemos una extensión al dataset para poner nuestros forecasts:"""

# Asegurar que el índice sea DatetimeIndex
if not isinstance(ts_bovino.index, pd.DatetimeIndex):
    ts_bovino.index = pd.to_datetime(ts_bovino.index)

# Asegurar frecuencia trimestral (inicio de trimestre)
if ts_bovino.index.freq is None:
    ts_bovino = ts_bovino.asfreq('QS')

# ts_bovino: index DatetimeIndex (trimestral, QS) y columna 'valor_exportado'
ts = ts_bovino.copy()
col_y = "valor_exportado"

forecast_horizon_q = 8  # <-- número de trimestres a pronosticar (ajusta)

last_date = ts.index[-1]

# Fechas futuras trimestrales (inicio de trimestre)
future_dates = pd.date_range(
    start=last_date + pd.offsets.QuarterBegin(1),
    periods=forecast_horizon_q,
    freq=ts.index.freq if ts.index.freq is not None else "QS"
)

# Construir índice extendido
extended_index = ts.index.append(future_dates)

ts_extended = pd.DataFrame(index=extended_index)
ts_extended[col_y] = ts[col_y].reindex(extended_index)

# Fitted + forecast del modelo ETS
ts_extended["Exponential_Smoothing"] = np.nan
ts_extended.loc[ts.index, "Exponential_Smoothing"] = exp_model.fittedvalues.reindex(ts.index)

ts_extended.loc[future_dates, "Exponential_Smoothing"] = exp_model.forecast(forecast_horizon_q).values

# Plot
plt.figure(figsize=(10, 6))
ax = sns.lineplot(data=ts_extended, x=ts_extended.index, y=col_y, label="Original")
sns.lineplot(data=ts_extended, x=ts_extended.index, y="Exponential_Smoothing", label="Exponential Smoothing")

plt.axvline(x=last_date, color="gray", linestyle="--", alpha=0.5, label="Forecast Start")
plt.title("Exponential Smoothing with Forecast")
plt.xlabel("")
plt.ylabel("valor_exportado")
plt.legend()

# Etiquetas en X solo por año (aunque los datos sean trimestrales)
ax.xaxis.set_major_locator(mdates.YearLocator())
ax.xaxis.set_major_formatter(mdates.DateFormatter("%Y"))
plt.xticks(rotation=45)

# Formato eje Y
ax.yaxis.set_major_formatter(ticker.FuncFormatter(lambda x, pos: f'${int(x):,}'))

plt.show()

"""# <font color='blue'> ARIMA

### Visualizando estacionalidad
"""

# Serie (trimestral)
y = ts_bovino["valor_exportado"].asfreq("QS").dropna()

def adf_test(series: pd.Series) -> float:
    """Return ADF p-value (autolag=AIC)."""
    return adfuller(series.dropna(), autolag="AIC")[1]

results = []
current = y.copy()

# d = 0..3
for d in range(0, 4):
    pval = adf_test(current)
    results.append({"d": d, "adf_pvalue": pval})
    current = current.diff().dropna()

adf_df = pd.DataFrame(results)
display(adf_df)

# Sugerir d: primer d con p<0.05
best_d = adf_df.loc[adf_df["adf_pvalue"] < 0.05, "d"].min()
print("Diferenciación recomendada (primer d con p<0.05):", best_d)

"""ACF y PACF"""

y = ts_bovino["valor_exportado"].asfreq("QS")

y_diff = y.diff().diff().dropna()

fig, axes = plt.subplots(1, 2, figsize=(12,5))

plot_acf(y_diff, ax=axes[0], lags=20)
axes[0].set_title("ACF")

plot_pacf(y_diff, ax=axes[1], lags=20, method="ywm")
axes[1].set_title("PACF")

plt.show()

"""### Parametros p y q

q = 0,1,2,4.
p = 0,1,2,3.

# ARIMA

Primer modelo:

- AR --> 3
- I --> 2
- MA --> 0
"""

order_arima = (3, 2, 0)

arima_model = ARIMA(ts_bovino.valor_exportado, order=order_arima)
arima_fit = arima_model.fit()

print(arima_fit.summary())

"""Todo mi bloque AR es correccto, pero vamos a evaluar si podemos agregar un componente MA.

Segundo modelo:

- AR --> 3
- I --> 2
- MA --> 4

Probando con el modelo (3,2,4), veo en los resultados que el bloque MA no es estadísticamente significativo. Por ello, me quedaré con el modelo (3,2,1).
"""

order_arima_2 = (3, 2, 1)

arima_model_2 = ARIMA(ts_bovino['valor_exportado'], order=order_arima_2)
arima_fit_2 = arima_model_2.fit()

print(arima_fit_2.summary())

# 1) Serie en niveles (real)
# -----------------------------
y = ts_bovino["valor_exportado"].asfreq("QS").dropna()

# -----------------------------
# 2) Fitted (in-sample) alineado
#    Empezar a evaluar/graficar desde la 2da observación
# -----------------------------
pred_in = arima_fit_2.get_prediction(start=y.index[0], end=y.index[-1])
y_hat = pred_in.predicted_mean.reindex(y.index)

# excluir la 1era observación fitted (y su y real correspondiente para evaluación)
y_eval = y.iloc[1:]
y_hat_eval = y_hat.iloc[1:]

mask = y_hat_eval.notna()

# -----------------------------
# 3) Métricas in-sample
# -----------------------------
mae = mean_absolute_error(y_eval[mask], y_hat_eval[mask])
mse = mean_squared_error(y_eval[mask], y_hat_eval[mask])
rmse = np.sqrt(mse)
mape = (np.abs((y_eval[mask] - y_hat_eval[mask]) / y_eval[mask])).mean() * 100

print("=== In-sample performance (desde 2da obs) ===")
print(f"MAE:  {mae:,.2f}")
print(f"RMSE: {rmse:,.2f}")
print(f"MAPE: {mape:,.2f}%")

# -----------------------------
# 4) Residuos + tests
# -----------------------------
resid = (y_eval[mask] - y_hat_eval[mask]).dropna()

print("\n=== Residual summary (desde 2da obs) ===")
print(resid.describe())

lb = acorr_ljungbox(resid, lags=[4, 8, 12], return_df=True)
print("\n=== Ljung-Box test (residual autocorrelation) ===")
display(lb)

plt.figure(figsize=(8, 4))
plot_acf(resid, lags=20)
plt.title("ACF de residuos (in-sample, desde 2da obs)")
plt.show()

# -----------------------------
# 5) Plot Actual vs Fitted (desde 2da obs)
# -----------------------------
plt.figure(figsize=(10, 5))
ax = sns.lineplot(x=y_eval.index, y=y_eval, label="Actual")
sns.lineplot(x=y_hat_eval.index, y=y_hat_eval, label="Fitted")

plt.title("ARIMA: Actual vs Fitted (in-sample, desde 2da obs)")
plt.xlabel("")
plt.ylabel("valor_exportado")

ax.xaxis.set_major_locator(mdates.YearLocator())
ax.xaxis.set_major_formatter(mdates.DateFormatter("%Y"))
plt.xticks(rotation=45)

ax.yaxis.set_major_formatter(ticker.FuncFormatter(lambda x, pos: f'${int(x):,}'))
plt.legend()
plt.show()

# Residuos en el tiempo
plt.figure(figsize=(10, 3))
sns.lineplot(x=resid.index, y=resid.values)
plt.axhline(0, linestyle="--", alpha=0.6)
plt.title("Residuos (Actual - Fitted) (desde 2da obs)")
plt.xlabel("")
plt.ylabel("Residuo")
plt.show()

# -----------------------------
# 6) Out-of-sample (últimos h trimestres)
# -----------------------------
h = 8
y_train, y_test = y.iloc[:-h], y.iloc[-h:]

order = arima_fit_2.model.order
fit_tt = ARIMA(y_train, order=order).fit()

fc_obj = fit_tt.get_forecast(steps=h)
fc_mean = fc_obj.predicted_mean.reindex(y_test.index)
fc_ci = fc_obj.conf_int().reindex(y_test.index)

mae_oos = mean_absolute_error(y_test, fc_mean)
mse_oos = mean_squared_error(y_test, fc_mean)
rmse_oos = np.sqrt(mse_oos)
mape_oos = (np.abs((y_test - fc_mean) / y_test)).mean() * 100

print("\n=== Out-of-sample performance (últimos h trimestres) ===")
print(f"MAE:  {mae_oos:,.2f}")
print(f"RMSE: {rmse_oos:,.2f}")
print(f"MAPE: {mape_oos:,.2f}%")

# Plot train/test + forecast
plt.figure(figsize=(10, 5))
ax = sns.lineplot(x=y_train.index, y=y_train, label="Train")
sns.lineplot(x=y_test.index, y=y_test, label="Test")
sns.lineplot(x=fc_mean.index, y=fc_mean, label="Forecast")

plt.fill_between(
    fc_ci.index,
    fc_ci.iloc[:, 0],
    fc_ci.iloc[:, 1],
    alpha=0.2,
    label="95% CI"
)

plt.axvline(x=y_test.index[0], color="gray", linestyle="--", alpha=0.6, label="Test start")
plt.title("ARIMA: Forecast vs Test")
plt.xlabel("")
plt.ylabel("valor_exportado")

ax.xaxis.set_major_locator(mdates.YearLocator())
ax.xaxis.set_major_formatter(mdates.DateFormatter("%Y"))
plt.xticks(rotation=45)

ax.yaxis.set_major_formatter(ticker.FuncFormatter(lambda x, pos: f'${int(x):,}'))
plt.legend()
plt.show()

# Serie histórica (niveles)
y = ts_bovino["valor_exportado"].asfreq("QS").dropna()
last_date = y.index[-1]

# Forecast a futuro (trimestres)
h = 8  # ajusta horizonte (ej. 8 trimestres = 2 años)
fc_obj = arima_fit_2.get_forecast(steps=h)
