"""# SARIMA

Dado que son datos trimestrales, vamos a probar agregando un elemento que nos permita reflejar estacionalidad.
"""

from statsmodels.tsa.statespace.sarimax import SARIMAX

# Serie en niveles
y = ts_bovino["valor_exportado"].asfreq("QS").dropna()

# Modelo SARIMAX con estacionalidad trimestral
sarima_model = SARIMAX(
    y,
    order=(3, 2, 0),            # (p,d,q)
    seasonal_order=(0, 0, 1, 4), # (P,D,Q,s)  s=4 trimestres
    enforce_stationarity=False,
    enforce_invertibility=False
)

sarima_fit = sarima_model.fit()

# Summary del modelo
print(sarima_fit.summary())

from statsmodels.tsa.statespace.sarimax import SARIMAX

