"""# ARIMAX

Quiero agregar ahora una variable exógena. Será el tipo de cambio peso/dólar.
"""

files.upload()

# Cargar dataset Banxico
fx = pd.read_csv("tipo_cambio_promedio_trimestral.csv")

fx

"""## Revisando estacionariedad de Tipo de Cambio"""

# Usar fecha como índice
fx["fecha"] = pd.to_datetime(fx["fecha"], errors="coerce")
fx = fx.set_index("fecha").sort_index()
fx.index.rename('Time', inplace=True)

# Serie (trimestral)
y = fx["tipo_cambio_promedio_trimestral"].asfreq("QS").dropna()

def adf_test(series: pd.Series) -> float:
    """Return ADF p-value (autolag=AIC)."""
    return adfuller(series.dropna(), autolag="AIC")[1]

results = []
current = y.copy()

# d = 0..3
for d in range(0, 4):
    pval = adf_test(current)
    results.append({"d": d, "adf_pvalue": pval})
    current = current.diff().dropna()

adf_df = pd.DataFrame(results)
display(adf_df)

# Sugerir d: primer d con p<0.05
best_d = adf_df.loc[adf_df["adf_pvalue"] < 0.05, "d"].min()
print("Diferenciación recomendada (primer d con p<0.05):", best_d)

# Ver resultado
display(fx.head())

# Serie objetivo
y = ts_bovino["valor_exportado"].asfreq("QS").dropna()

y.head(5)

X = fx["tipo_cambio_promedio_trimestral"].reindex(y.index).ffill().bfill().to_frame("tipo_cambio_fix")

from statsmodels.tsa.statespace.sarimax import SARIMAX

arimax_model = SARIMAX(
    y,
    exog=X,
    order=(3,2,1),
    enforce_stationarity=False,
    enforce_invertibility=False
)

arimax_fit = arimax_model.fit()

print(arimax_fit.summary())

"""### LAG"""

# Create lagged exogenous variable (1 quarter)
X_lag1 = X.copy()
X_lag1["tipo_cambio_lag1"] = X_lag1["tipo_cambio_fix"].shift(1)

# Keep only the lag variable
X_lag1 = X_lag1[["tipo_cambio_lag1"]]

display(X_lag1.head())

y_lag = y.loc[X_lag1.index]

# Remove NA created by lag
mask = X_lag1.notna().all(axis=1)

y_lag = y_lag[mask]
X_lag1 = X_lag1[mask]

from statsmodels.tsa.statespace.sarimax import SARIMAX

arimax_lag1_model = SARIMAX(
    y_lag,
    exog=X_lag1,
    order=(3,2,1),
    enforce_stationarity=False,
    enforce_invertibility=False
)

arimax_lag1_fit = arimax_lag1_model.fit()

print(arimax_lag1_fit.summary())

"""## Rendimiento de modelo ARIMAX"""

# -----------------------------
# 1) Serie en niveles (real) + exógena alineada
# -----------------------------
y = ts_bovino["valor_exportado"].asfreq("QS").dropna()

# X_lag1 debe tener el mismo índice trimestral que y
# (si no, alínea)
X_exog = X_lag1.reindex(y.index)

# Quita filas con NA en exog (por el lag)
mask_exog = X_exog.notna().all(axis=1)
y = y[mask_exog]
X_exog = X_exog[mask_exog]

# -----------------------------
# 2) Fitted (in-sample)
# -----------------------------
pred_in = arimax_lag1_fit.get_prediction(start=y.index[0], end=y.index[-1], exog=X_exog)
y_hat = pred_in.predicted_mean.reindex(y.index)

# excluir primera observación (opcional, como hiciste antes)
y_eval = y.iloc[1:]
y_hat_eval = y_hat.iloc[1:]
X_eval = X_exog.iloc[1:]

mask = y_hat_eval.notna()

# -----------------------------
# 3) Métricas in-sample
# -----------------------------
mae = mean_absolute_error(y_eval[mask], y_hat_eval[mask])
mse = mean_squared_error(y_eval[mask], y_hat_eval[mask])
rmse = np.sqrt(mse)
mape = (np.abs((y_eval[mask] - y_hat_eval[mask]) / y_eval[mask])).mean() * 100

print("=== In-sample performance (ARIMAX, desde 2da obs) ===")
print(f"MAE:  {mae:,.2f}")
print(f"RMSE: {rmse:,.2f}")
print(f"MAPE: {mape:,.2f}%")

# -----------------------------
# 4) Residuos
# -----------------------------
resid = (y_eval[mask] - y_hat_eval[mask]).dropna()

print("\n=== Residual summary ===")
print(resid.describe())

lb = acorr_ljungbox(resid, lags=[4, 8, 12], return_df=True)
print("\n=== Ljung-Box test ===")
display(lb)

plt.figure(figsize=(8, 4))
plot_acf(resid, lags=20)
plt.title("ACF de residuos (ARIMAX)")
plt.show()

# -----------------------------
# 5) Plot Actual vs Fitted
# -----------------------------
plt.figure(figsize=(10, 5))
ax = sns.lineplot(x=y_eval.index, y=y_eval, label="Actual")
sns.lineplot(x=y_hat_eval.index, y=y_hat_eval, label="Fitted")

plt.title("ARIMAX: Actual vs Fitted")
plt.xlabel("")
plt.ylabel("valor_exportado")

ax.xaxis.set_major_locator(mdates.YearLocator())
ax.xaxis.set_major_formatter(mdates.DateFormatter("%Y"))
plt.xticks(rotation=45)

ax.yaxis.set_major_formatter(ticker.FuncFormatter(lambda x, pos: f'${int(x):,}'))
plt.legend()
plt.show()

# -----------------------------
# 6) Residuos en el tiempo
# -----------------------------
plt.figure(figsize=(10, 3))
sns.lineplot(x=resid.index, y=resid.values)
plt.axhline(0, linestyle="--", alpha=0.6)

plt.title("Residuos (Actual - Fitted) (ARIMAX)")
plt.xlabel("")
plt.ylabel("Residuo")
plt.show()

# -----------------------------
# 7) Out-of-sample test (últimos h trimestres)
# -----------------------------
h = 8

y_train, y_test = y.iloc[:-h], y.iloc[-h:]
X_train, X_test = X_exog.iloc[:-h], X_exog.iloc[-h:]

order = arimax_lag1_fit.model.order
seasonal_order = arimax_lag1_fit.model.seasonal_order

fit_tt = SARIMAX(
    y_train,
    exog=X_train,
    order=order,
    seasonal_order=seasonal_order,
    enforce_stationarity=False,
    enforce_invertibility=False
).fit(disp=False)

fc_obj = fit_tt.get_forecast(steps=h, exog=X_test)

fc_mean = fc_obj.predicted_mean.reindex(y_test.index)
fc_ci = fc_obj.conf_int().reindex(y_test.index)

mae_oos = mean_absolute_error(y_test, fc_mean)
mse_oos = mean_squared_error(y_test, fc_mean)
rmse_oos = np.sqrt(mse_oos)
mape_oos = (np.abs((y_test - fc_mean) / y_test)).mean() * 100

print("\n=== Out-of-sample performance (ARIMAX) ===")
print(f"MAE:  {mae_oos:,.2f}")
print(f"RMSE: {rmse_oos:,.2f}")
print(f"MAPE: {mape_oos:,.2f}%")

# -----------------------------
# 8) Forecast vs Test plot
# -----------------------------
plt.figure(figsize=(10, 5))
ax = sns.lineplot(x=y_train.index, y=y_train, label="Train")
sns.lineplot(x=y_test.index, y=y_test, label="Test")
sns.lineplot(x=fc_mean.index, y=fc_mean, label="Forecast")

plt.fill_between(
    fc_ci.index,
    fc_ci.iloc[:, 0],
    fc_ci.iloc[:, 1],
    alpha=0.2,
    label="95% CI"
)

plt.axvline(x=y_test.index[0], color="gray", linestyle="--", alpha=0.6, label="Test start")

plt.title("ARIMAX: Forecast vs Test")
plt.xlabel("")
plt.ylabel("valor_exportado")

ax.xaxis.set_major_locator(mdates.YearLocator())
ax.xaxis.set_major_formatter(mdates.DateFormatter("%Y"))
plt.xticks(rotation=45)

ax.yaxis.set_major_formatter(ticker.FuncFormatter(lambda x, pos: f'${int(x):,}'))
plt.legend()
